import React from 'react';
import { useDrop } from 'react-dnd';
import DraggablePlayer from './DraggablePlayer';
import './TeamDisplay.css';

const TeamDisplay = ({ teams, showDetails, calculateAverageRating, movePlayer }) => {

  // Function to handle dropping players into a team
  const getDropHandlerForTeam = (teamIndex) => {
    const [{ isOver }, dropRef] = useDrop({
      accept: 'PLAYER',
      drop: (draggedItem) => {
        movePlayer(draggedItem, teamIndex); // Handle player drop into a team
      },
      collect: (monitor) => ({
        isOver: monitor.isOver(),
      }),
    });
    return { isOver, dropRef };
  };

  return (
    <div className="teams-container">
      {teams.map((team, index) => {
        const { isOver, dropRef } = getDropHandlerForTeam(index); // Generate drop handler for each team

        return (
          <div ref={dropRef} key={index} className={`team-card ${isOver ? 'highlight-drop-zone' : ''}`}>
            <h4>
              Team {index + 1}: {team.length} players
            </h4>
            <h4>
              Average Rating: {calculateAverageRating(team).toFixed(2)}
            </h4>
            <table className="table table-striped table-bordered">
              <thead>
                <tr>
                  {showDetails && <th></th>} {/* Add empty header for draggable */}
                  {showDetails && <th>Rating</th>}
                </tr>
              </thead>
              <tbody>
                {team.map((player) => (
                  <DraggablePlayer
                    key={player.id}
                    player={player}
                    teamIndex={index}
                    showDetails={showDetails}
                  />
                ))}
              </tbody>
            </table>
          </div>
        );
      })}
    </div>
  );
};

export default TeamDisplay;
